import{_ as e,o as i,c as l,ae as o}from"./chunks/framework.CyZiF_rV.js";const f=JSON.parse('{"title":"Проверка счета-фактуры","description":"","frontmatter":{},"headers":[],"relativePath":"ru/faktury/weryfikacja-faktury.md","filePath":"ru/faktury/weryfikacja-faktury.md"}'),r={name:"ru/faktury/weryfikacja-faktury.md"};function t(d,a,n,c,h,u){return i(),l("div",null,[...a[0]||(a[0]=[o('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/faktury/weryfikacja-faktury.md" target="_blank" rel="noreferrer">faktury/weryfikacja-faktury.md</a></p></blockquote><h1 id="проверка-счета-фактуры" tabindex="-1">Проверка счета-фактуры <a class="header-anchor" href="#проверка-счета-фактуры" aria-label="Permalink to &quot;Проверка счета-фактуры&quot;">​</a></h1><p>15.01.2026</p><p>Счет-фактура, отправляемая в систему KSeF, подлежит ряду технических и семантических проверок. Проверка включает следующие критерии:</p><h2 id="соответствие-схеме-xsd" tabindex="-1">Соответствие схеме XSD <a class="header-anchor" href="#соответствие-схеме-xsd" aria-label="Permalink to &quot;Соответствие схеме XSD&quot;">​</a></h2><p>Счет-фактура должна быть подготовлена в формате XML, закодирована в UTF-8 без знака BOM (первые 3 байта 0xEF 0xBB 0xBF), соответствовать заявленной схеме, указанной при открытии сессии.</p><h2 id="уникальность-счета-фактуры" tabindex="-1">Уникальность счета-фактуры <a class="header-anchor" href="#уникальность-счета-фактуры" aria-label="Permalink to &quot;Уникальность счета-фактуры&quot;">​</a></h2><ul><li>KSeF обнаруживает дубликаты счетов-фактур глобально, на основе данных, хранящихся в системе. Критерием идентификации дубликата является комбинация: <ol><li>NIP продавца (<code>Podmiot1:NIP</code>)</li><li>Вид счета-фактуры (<code>RodzajFaktury</code>)</li><li>Номер счета-фактуры (<code>P_2</code>)</li></ol></li><li>В случае дубликата возвращается код ошибки 440 («Дубликат счета-фактуры»).</li><li>Уникальность счета-фактуры поддерживается в KSeF в течение 10 полных лет, считаемых от конца календарного года, в котором был выставлен счет-фактура.</li><li>Критерий уникальности всегда относится к продавцу (Podmiot1:NIP). В случае, когда от имени одного и того же субъекта счета-фактуры выставляют разные единицы (например, филиалы, организационные единицы JST, другие уполномоченные субъекты), они должны согласовать принципы нумерации, чтобы избежать дубликатов.</li></ul><h2 id="проверка-дат" tabindex="-1">Проверка дат <a class="header-anchor" href="#проверка-дат" aria-label="Permalink to &quot;Проверка дат&quot;">​</a></h2><p>Дата выставления счета-фактуры (<code>P_1</code>) не может быть позднее даты принятия документа в систему KSeF.</p><h2 id="проверка-номера-nip" tabindex="-1">Проверка номера NIP <a class="header-anchor" href="#проверка-номера-nip" aria-label="Permalink to &quot;Проверка номера NIP&quot;">​</a></h2><ul><li>Проверка контрольной суммы NIP для: <code>Podmiot1</code>, <code>Podmiot2</code>, <code>Podmiot3</code> и <code>PodmiotUpowazniony</code> (если присутствует).</li><li>Касается только производственной среды.</li></ul><h2 id="проверка-номера-nip-во-внутреннем-идентификаторе" tabindex="-1">Проверка номера NIP во внутреннем идентификаторе <a class="header-anchor" href="#проверка-номера-nip-во-внутреннем-идентификаторе" aria-label="Permalink to &quot;Проверка номера NIP во внутреннем идентификаторе&quot;">​</a></h2><ul><li>Проверка контрольной суммы NIP во внутреннем идентификаторе (<code>InternalId</code>) для <code>Podmiot3</code> - если данный идентификатор присутствует.</li><li>Касается только производственной среды.</li></ul><h2 id="размер-фаила" tabindex="-1">Размер файла <a class="header-anchor" href="#размер-фаила" aria-label="Permalink to &quot;Размер файла&quot;">​</a></h2><ul><li>Максимальный размер счета-фактуры без вложений: <strong>1 МБ *</strong> (1 000 000 байт).</li><li>Максимальный размер счета-фактуры с вложениями: <strong>3 МБ *</strong> (3 000 000 байт).</li></ul><h2 id="количественные-ограничения" tabindex="-1">Количественные ограничения <a class="header-anchor" href="#количественные-ограничения" aria-label="Permalink to &quot;Количественные ограничения&quot;">​</a></h2><ul><li>Максимальное количество счетов-фактур в одной сессии (как интерактивной, так и пакетной) составляет 10 000 *.</li><li>В рамках пакетной отправки можно отправить максимально 50 ZIP-файлов; размер каждого файла до шифрования не может превышать 100 МБ (100 000 000 байт), а общий размер ZIP-пакета - 5 ГБ (5 000 000 000 байт).</li></ul><h2 id="корректное-шифрование" tabindex="-1">Корректное шифрование <a class="header-anchor" href="#корректное-шифрование" aria-label="Permalink to &quot;Корректное шифрование&quot;">​</a></h2><ul><li>Счет-фактура должна быть зашифрована алгоритмом AES-256-CBC (симметричный ключ 256 бит, IV 128 бит, с дополнением (padding) PKCS#7).</li><li>Симметричный ключ зашифрован алгоритмом RSAES-OAEP (SHA-256/MGF1).</li></ul><h2 id="соответствие-метаданных-счета-фактуры-в-интерактивнои-сессии" tabindex="-1">Соответствие метаданных счета-фактуры в интерактивной сессии <a class="header-anchor" href="#соответствие-метаданных-счета-фактуры-в-интерактивнои-сессии" aria-label="Permalink to &quot;Соответствие метаданных счета-фактуры в интерактивной сессии&quot;">​</a></h2><ul><li>Вычисление и проверка хэша счета-фактуры вместе с размером файла.</li><li>Вычисление и проверка хэша зашифрованной счета-фактуры вместе с размером файла.</li></ul><h2 id="ограничения-касательно-вложении" tabindex="-1">Ограничения касательно вложений <a class="header-anchor" href="#ограничения-касательно-вложении" aria-label="Permalink to &quot;Ограничения касательно вложений&quot;">​</a></h2><ul><li>Отправка счетов-фактур с вложениями разрешена только в пакетном режиме.<br><strong>Исключение:</strong> В случае отправки <a href="./../offline/korekta-techniczna.html">технической корректировки офлайн счета-фактуры</a> допускается использование интерактивной сессии.</li><li>Возможность отправки счетов-фактур с вложениями требует предварительной регистрации этой опции в службе <code>e-Urząd Skarbowy</code>.</li></ul><h2 id="требования-касательно-полномочии" tabindex="-1">Требования касательно полномочий <a class="header-anchor" href="#требования-касательно-полномочии" aria-label="Permalink to &quot;Требования касательно полномочий&quot;">​</a></h2><p>Отправка счета-фактуры в KSeF требует наличия соответствующих полномочий на ее выставление в контексте данного субъекта.</p><p>* <strong>Внимание:</strong> Если в бизнес-сценариях организации доступные <a href="./../limity/limity.html">лимиты</a> недостаточны, просим обратиться в отдел поддержки KSeF для проведения индивидуального анализа и подбора соответствующего решения.</p>',27)])])}const k=e(r,[["render",t]]);export{f as __pageData,k as default};
